// generar_257_secciones_bioquimico_hemograma.js
// CHIQUI Entre Señales — Bioquímico y Hemograma en secciones colapsables
//
// Los perfiles bioquímico (15 parámetros) y hemograma (22) eran listas
// planas y largas, mientras orina y tiroides ya tenían secciones
// colapsables. Ahora los cuatro tipos comparten la misma organización,
// siguiendo la agrupación de los informes de laboratorio reales:
//
// 🧪 Perfil bioquímico → 4 secciones:
//   - Proteínas: Proteínas Totales, Albúmina, Globulinas
//   - Función hepática: Bilirrubina Total, Fosfatasa Alcalina,
//     GPT/ALT, GOT/AST, GGT
//   - Función renal: Urea, Nus (BUN), Creatinina, Fósforo
//   - Metabolismo y minerales: Glucosa, Colesterol, Calcio
//
// 🩸 Hemograma → 4 secciones:
//   - Serie roja: Eritrocitos, Hematocrito, Hemoglobina, VCM, HCM, CHCM
//   - Plaquetas
//   - Serie blanca (%): Leucocitos + porcentajes del leucograma
//   - Serie blanca (absolutos): los valores absolutos
//
// Cómo funciona (reutiliza el mecanismo existente de orina/tiroides):
// - Al cargar un examen nuevo, las secciones aparecen COLAPSADAS con
//   contador de valores completados — mucho menos abrumador.
// - En el historial del tutor, cada examen guardado muestra los
//   subtítulos de sección entre los parámetros.
// - En /vet, la tabla completa del examen también muestra los
//   subtítulos (nuevo mapa de secciones en ExamenesLabVet, espejo de
//   las plantillas del tutor).
//
// IMPORTANTE sobre datos existentes: los NOMBRES de los parámetros no
// cambian, así que los rangos por defecto y los exámenes ya guardados
// siguen calzando. En el bioquímico se reordenaron los parámetros para
// que cada sección quede contigua — los exámenes bioquímicos guardados
// ANTES de este cambio conservan su orden original, por lo que en su
// historial algún subtítulo puede repetirse (efecto visual menor, solo
// en exámenes antiguos). Los nuevos se guardan ya agrupados.
//
// Orina, tiroides y test rápido quedan intactos.
//
// No hay SQL.
//
// Uso:
//   node generar_257_secciones_bioquimico_hemograma.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "components/ExamenesLab.tsx",
    base64: ""
  },
  {
    ruta: "components/ExamenesLabVet.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 2 archivos escritos. git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
